using System;
using System.Reflection;
using System.Linq;

var path = Environment.GetFolderPath(Environment.SpecialFolder.UserProfile) +
    "/.nuget/packages/modelcontextprotocol.core/1.2.0/lib/net9.0/ModelContextProtocol.Core.dll";
var asm = Assembly.LoadFrom(path);

// McpServerTool class
var tool = asm.GetTypes().First(t => t.FullName == "ModelContextProtocol.Server.McpServerTool");
Console.WriteLine($"=== {tool.FullName} (Base: {tool.BaseType?.Name}) ===");
foreach (var m in tool.GetMethods(BindingFlags.Public | BindingFlags.Static | BindingFlags.DeclaredOnly))
    Console.WriteLine($"  Static: {m.Name}({string.Join(", ", m.GetParameters().Select(p => $"{p.ParameterType.Name}"))})");
foreach (var p in tool.GetProperties(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly))
    Console.WriteLine($"  Prop: {p.Name} : {p.PropertyType.Name}");

// Extension methods on IMcpServerBuilder
Console.WriteLine("\n=== WithTools overloads ===");
var ext = asm.GetTypes()
    .Concat(Assembly.LoadFrom(path.Replace("Core", "")).GetTypes())
    .Where(t => t.Name == "McpServerBuilderExtensions")
    .SelectMany(t => t.GetMethods(BindingFlags.Public | BindingFlags.Static))
    .Where(m => m.Name.Contains("Tool") || m.Name.Contains("Stdio"))
    .ToList();
foreach (var m in ext)
    Console.WriteLine($"  {m.Name}({string.Join(", ", m.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"))})");
