using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

[McpServerToolType]
public sealed class WeatherTools
{
    [McpServerTool(Name = "get_forecast"), Description("Get weather forecast for a location.")]
    public async Task<string> GetForecast(
        IHttpClientFactory httpClientFactory,
        [Description("Latitude of the location")] double latitude,
        [Description("Longitude of the location")] double longitude,
        [Description("Number of forecast days (1-7)")] int forecastDays = 3)
    {
        var client = httpClientFactory.CreateClient("WeatherApi");
        var url = $"v1/forecast?latitude={latitude}&longitude={longitude}" +
                  $"&daily=temperature_2m_max,temperature_2m_min,precipitation_sum" +
                  $"&forecast_days={Math.Clamp(forecastDays, 1, 7)}&timezone=auto";

        using var response = await client.GetAsync(url);
        response.EnsureSuccessStatusCode();

        using var doc = await JsonDocument.ParseAsync(await response.Content.ReadAsStreamAsync());
        var daily = doc.RootElement.GetProperty("daily");

        var dates = daily.GetProperty("time").EnumerateArray().Select(e => e.GetString()).ToList();
        var highs = daily.GetProperty("temperature_2m_max").EnumerateArray().Select(e => e.GetDouble()).ToList();
        var lows = daily.GetProperty("temperature_2m_min").EnumerateArray().Select(e => e.GetDouble()).ToList();
        var precip = daily.GetProperty("precipitation_sum").EnumerateArray().Select(e => e.GetDouble()).ToList();

        var lines = dates.Select((date, i) =>
            $"{date}: High {highs[i]}°C, Low {lows[i]}°C, Precip {precip[i]}mm");

        return string.Join("\n", lines);
    }

    [McpServerTool(Name = "get_current_weather"), Description("Get current weather conditions for a location.")]
    public async Task<string> GetCurrentWeather(
        IHttpClientFactory httpClientFactory,
        [Description("Latitude of the location")] double latitude,
        [Description("Longitude of the location")] double longitude)
    {
        var client = httpClientFactory.CreateClient("WeatherApi");
        var url = $"v1/forecast?latitude={latitude}&longitude={longitude}" +
                  "&current=temperature_2m,relative_humidity_2m,wind_speed_10m,weather_code" +
                  "&timezone=auto";

        using var response = await client.GetAsync(url);
        response.EnsureSuccessStatusCode();

        using var doc = await JsonDocument.ParseAsync(await response.Content.ReadAsStreamAsync());
        var current = doc.RootElement.GetProperty("current");

        var temp = current.GetProperty("temperature_2m").GetDouble();
        var humidity = current.GetProperty("relative_humidity_2m").GetInt32();
        var wind = current.GetProperty("wind_speed_10m").GetDouble();
        var code = current.GetProperty("weather_code").GetInt32();

        return $"Temperature: {temp}°C\nHumidity: {humidity}%\nWind: {wind} km/h\nCondition: {WeatherCodeToDescription(code)}";
    }

    private static string WeatherCodeToDescription(int code) => code switch
    {
        0 => "Clear sky",
        1 or 2 or 3 => "Partly cloudy",
        45 or 48 => "Foggy",
        51 or 53 or 55 => "Drizzle",
        61 or 63 or 65 => "Rain",
        71 or 73 or 75 => "Snow",
        95 => "Thunderstorm",
        _ => $"Code {code}"
    };
}

